using UnityEngine;

public class VisionCone : MonoBehaviour {
    public int rayCount = 130;
    public float viewRadius = 10f;
    public float viewAngle = 90f;
    public LayerMask obstacleMask;
    public LayerMask targetMask;

    public bool IsTargetVisible(GameObject target) {
        Vector3 directionToTarget = (target.transform.position - transform.position).normalized;
        float angleToTarget = Vector3.Angle(transform.forward, directionToTarget);

        if (angleToTarget > viewAngle / 2) return false;

        if (Physics.Raycast(transform.position, directionToTarget, out RaycastHit hit, viewRadius, obstacleMask)) {
            if (hit.collider.gameObject == target) {
                return true;
            }
        }
        return false;
    }

    void Update() {
        // Cast rays in a cone pattern (simplified example)
        for (int i = 0; i < rayCount; i++) {
            float angle = transform.eulerAngles.y - viewAngle / 2 + (float)i / rayCount * viewAngle;
            Vector3 dir = AngleToVector(angle);
            Ray ray = new Ray(transform.position, dir);

            if (Physics.Raycast(ray, out RaycastHit hit, viewRadius)) {
                if (targetMask == (targetMask | (1 << hit.collider.gameObject.layer))) {
                    Debug.DrawRay(transform.position, dir * hit.distance, Color.red);
                } else {
                    Debug.DrawRay(transform.position, dir * hit.distance, Color.green);
                }
            } else {
                Debug.DrawRay(transform.position, dir * viewRadius, Color.blue);
            }
        }
    }

    Vector3 AngleToVector(float angle) {
        float rad = angle * Mathf.Deg2Rad;
        return new Vector3(Mathf.Cos(rad), 0, Mathf.Sin(rad));
    }
}
